    "code": "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Responsive Navbar</title>\n\n  <style> \n    /* Basic Reset */\n* {\n  box-sizing: border-box;\n  margin: 0;\n  padding: 0;\n}\n\nbody {\n  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;\n}\n\n/* Navbar Container */\n.navbar {\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  background-color: #2c3e50;\n  padding: 1rem 5%;\n}\n\n/* Logo Styling */\n.navbar-logo a {\n  color: #ffffff;\n  text-decoration: none;\n  font-size: 1.5rem;\n  font-weight: bold;\n  letter-spacing: 1px;\n}\n\n/* Center Links */\n.navbar-links {\n  display: flex;\n  list-style: none;\n  gap: 2rem; /* Spacing between links */\n}\n\n.navbar-links a {\n  color: #ecf0f1;\n  text-decoration: none;\n  font-size: 1rem;\n  transition: color 0.3s ease;\n}\n\n.navbar-links a:hover {\n  color: #3498db;\n}\n\n/* Right Action Button */\n.login-btn {\n  background-color: #3498db;\n  color: white;\n  border: none;\n  padding: 0.6rem 1.2rem;\n  border-radius: 5px;\n  font-size: 1rem;\n  cursor: pointer;\n  transition: background-color 0.3s ease;\n}\n\n.login-btn:hover {\n  background-color: #2980b9;\n}\n\n/* Responsive Design for Mobile Devices */\n@media screen and (max-width: 768px) {\n  .navbar {\n    flex-direction: column;\n    padding: 1rem;\n  }\n\n  .navbar-logo {\n    margin-bottom: 1rem;\n  }\n\n  .navbar-links {\n    flex-direction: column;\n    width: 100%;\n    text-align: center;\n    gap: 1rem;\n    margin-bottom: 1rem;\n  }\n\n  .navbar-actions {\n    width: 100%;\n  }\n\n  .login-btn {\n    width: 100%;\n  }\n}\n    </style>\n</head>\n<body>\n\n  <nav class=\"navbar\">\n    <div class=\"navbar-logo\">\n      <a href=\"#\">BrandLogo</a>\n    </div>\n\n    <ul class=\"navbar-links\">\n      <li><a href=\"#\">Home</a></li>\n      <li><a href=\"#\">Features</a></li>\n      <li><a href=\"#\">Pricing</a></li>\n    </ul>\n\n    <div class=\"navbar-actions\">\n      <button class=\"login-btn\">Login</button>\n    </div>\n  </nav>\n\n</body>\n</html>"
